const intent = $json.intent || '';
const params = $json.intentParams || {};
const accessToken = $json.accessToken || '';

if (!accessToken) { return [{ json: { ...$json, responseText: '⚠️ Google Auth failed: no access token.', success: false } }]; }

let endpoint, queryParams, method = 'GET', body = null;
const calendarId = params.calendar_id || 'primary';

if (intent === 'calendar_list') {
  endpoint = `https://www.googleapis.com/calendar/v3/calendars/${calendarId}/events`;
  const now = new Date();
  const timeMin = params.time_min || now.toISOString();
  const timeMax = params.time_max || new Date(now.getTime() + 7 * 86400000).toISOString();
  queryParams = { maxResults: Math.min(params.max_results || 10, 50), timeMin, timeMax, orderBy: 'startTime', singleEvents: true };
} else if (intent === 'calendar_create') {
  const { summary, start, end, description, location, attendees } = params;
  if (!summary || !start || !end) { return [{ json: { ...$json, responseText: '❗ summary, start, and end are required.', success: false } }]; }
  endpoint = `https://www.googleapis.com/calendar/v3/calendars/${calendarId}/events`;
  method = 'POST';
  body = { summary, start: { dateTime: start }, end: { dateTime: end } };
  if (description) body.description = description;
  if (location) body.location = location;
  if (attendees) body.attendees = attendees;
} else if (intent === 'calendar_delete') {
  const eventId = params.event_id || params.id;
  if (!eventId) return [{ json: { ...$json, responseText: '❗ Event ID required.', success: false } }];
  endpoint = `https://www.googleapis.com/calendar/v3/calendars/${calendarId}/events/${eventId}`;
  method = 'DELETE';
} else { return [{ json: { ...$json, responseText: '❓ Unknown Calendar intent: ' + intent, success: false } }]; }

return [{ json: { ...$json, apiEndpoint: endpoint, apiParams: queryParams, apiMethod: method, apiBody: body, bearerToken: accessToken, _ctx: { intent, params, accessToken, source: $json.source, userId: $json.userId, sessionId: $json.sessionId, inputText: $json.inputText } } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const items = $json.items || [];
if ($json.id && ($json.status === 'cancelled' || $json.summary)) {
  return [{ json: { ...ctx, responseText: '✅ Calendar operation completed successfully.', success: true, intent: ctx.intent } }];
}
if (items.length === 0) { return [{ json: { ...ctx, responseText: '📅 No upcoming events found.', success: true, intent: ctx.intent } }]; }
let text = '📅 Upcoming Events:

';
items.forEach((ev, i) => {
  const start = ev.start?.dateTime || ev.start?.date || 'TBD';
  const summary = ev.summary || 'Untitled';
  const location = ev.location ? `\n📍 ${ev.location}` : '';
  text += `<b>${start}</b>\n✅ ${summary}${location}\n\n`;
});
return [{ json: { ...ctx, responseText: text, success: true, intent: ctx.intent } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) { console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](JSON.stringify({ timestamp: new Date().toISOString(), level, traceId: ctx.sessionId || 'unknown', workflow: 'calendar-agent', message, meta })); }
};
const statusCode = $json.statusCode || $json.error?.statusCode || 0;
const statusMessage = $json.statusMessage || $json.error?.message || 'Unknown error';
if (statusCode === 401) {
  jarvisLog('warn', 'Token expired, attempting refresh', { intent: ctx.intent });
  try {
    const authRes = await $helpers.httpRequest({ method: 'POST', url: 'https://oauth2.googleapis.com/token', headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body: 'client_id=' + encodeURIComponent($env.GOOGLE_CLIENT_ID) + '&client_secret=' + encodeURIComponent($env.GOOGLE_CLIENT_SECRET) + '&refresh_token=' + encodeURIComponent($env.GOOGLE_REFRESH_TOKEN) + '&grant_type=refresh_token', timeout: 15000 });
    const retryRes = await $helpers.httpRequest({ method: $('Build Request').first().json.apiMethod || 'GET', url: $('Build Request').first().json.apiEndpoint, headers: { 'Authorization': 'Bearer ' + authRes.access_token }, body: $('Build Request').first().json.apiBody, timeout: 15000 });
    return [{ json: { ...retryRes, _ctx: ctx } }];
  } catch (retryErr) {
    jarvisLog('error', 'Auth retry failed', { intent: ctx.intent, error: retryErr.message });
    return [{ json: { ...ctx, responseText: '⚠️ Authentication failed after refresh. Please re-authenticate Google OAuth.', success: false, intent: ctx.intent } }];
  }
}
jarvisLog('error', 'API request failed', { intent: ctx.intent, statusCode, statusMessage });
return [{ json: { ...ctx, responseText: '⚠️ Could not complete your request. API returned error ' + statusCode + ': ' + statusMessage + '. Please try again.', success: false, intent: ctx.intent, error: { statusCode, provider: 'calendar', intent: ctx.intent } } }];
